   110→      if (result.left is NetworkFailure) {
   111→        return Left(Failure.network(
   112→          code: methodFc.position('001'),
   113→          description: (l10n) =>
   114→              l10n.auth_client__failed_to_authenticate_check_network,
   115→          underlyingException: result.left.underlyingException,
   116→        ));
   117→      }
   118→      if (result.left is InvalidSessionFailure) {
   119→        final e = result.left.underlyingException;
   120→        if (e is AuthException) {
   121→          return Left(await _processAuthException(
   122→            e,
   123→            email: email,
   124→            password: password,
   125→          ));
   126→        }
   127→      }
   128→      return Left(result.left);
   129→    }
   130→
   131→    late String userId;
   132→    try {
   133→      userId = await AuthUtils.instance.getUserId();
   134→    } catch (e, stackTrace) {
   135→      _logger.e('failed to get userId', ex: e, stacktrace: stackTrace);
   136→      return Left(Failure.undefined(
   137→        code: methodFc.position('002'),
   138→        underlyingException: e,
   139→        stackTrace: stackTrace,
   140→      ));
   141→    }
   142→
   143→    await _profileStorage.setEmail(email);
   144→    if (saveCredentials) {
   145→      // Cache user password
   146→      await _profileStorage.setPassword(password);
   147→    } else {
   148→      // Remove cached user password
   149→      await _profileStorage.setPassword(null);
   150→    }
   151→
   152→    await _profileStorage.setUserId(userId);
   153→
   154→    // Get team_id and role of the user using direct API call
   155→    // This avoids circular dependency with Repository
   156→    final userInfoResult = await _apiClient.request(
   157→      method: 'GET',
   158→      path: '/users/me',
   159→      responseMapper: UserDetailResponse.fromJson,
   160→    );
   161→    if (userInfoResult.hasLeft) {
   162→      return Left(userInfoResult.left);
   163→    }
   164→
   165→    final user = userInfoResult.right.user;
   166→    final teamId = user.teams
   167→        .where((t) =>
   168→            user.givenUserRoles[t.id!]
   169→                ?.where((r) => !r.deleteFlag)
   170→                .isNotEmpty ??
   171→            false)
   172→        .firstOrNull
   173→        ?.id;
   174→    if (teamId == null) {
   175→      return Left(Failure.undefined(
   176→        code: methodFc.position('003'),
   177→        description: (l10n) => 'User does not belong to any team',
   178→      ));
   179→    }
   180→
   181→    // Cache team_id and role
   182→    await _profileStorage.setTeamId(teamId);
   183→
   184→    return const Right(true);
