   207→      if (emailStatusResult is UnconfirmedEmailFailure) {
   208→        return emailStatusResult;
   209→      }
   210→      // それ以外の場合は、パスワード間違いエラーを返す
   211→      return Failure.incorrectPassword(
   212→        code: methodFc.position('001'),
   213→        email: email,
   214→      );
   215→    }
   216→    if (isUserNotFound) {
   217→      return await _getEmailVerificationStatus(
   218→        email: email,
   219→        password: password,
   220→      );
   221→    }
   222→
   223→    // アカウント削除後にユーザーが削除予定に入っている場合に signIn しようとすると
   224→    // このエラーになる。この場合は未登録メールアドレスエラーを返す。
   225→    final errorCode = methodFc.position('003');
   226→    if (errorCode == 'EM-AAC-PAEX-003') {
   227→      return Failure.unregisteredEmail(
   228→        code: errorCode,
   229→        email: email,
   230→      );
   231→    }
   232→
   233→    // それ以外の認証エラーは UndefinedFailure として扱う
   234→    return Failure.undefined(
   235→      code: methodFc.position('004'),
   236→      description: (l10n) =>
   237→          l10n.auth_client__failed_to_authenticate_received_error_response,
   238→      underlyingException: e,
   239→    );
   240→  }
