   242→  Future<Failure> _getEmailVerificationStatus({
   243→    required String email,
   244→    required String password,
   245→  }) async {
   246→    final methodFc = _fc.category('GVS');
   247→
   248→    // Run the query and return result.
   249→    final result = await _apiClient.request(
   250→      method: 'GET',
   251→      path:
   252→          '/auth/users/verification-status?email=${Uri.encodeQueryComponent(email)}',
   253→      responseMapper: EmailVerificationStatusResponse.fromJson,
   254→      authenticated: false,
   255→    );
   256→    if (result.hasLeft) {
   257→      return result.left;
   258→    }
   259→
   260→    final status = result.right.status;
   261→    switch (status) {
   262→      case EmailVerificationStatus.notVerified:
   263→        // Save email and password to localStorage for UnconfirmedEmailFailure
   264→        // To ensure the correct email and password is used for resending verification code
   265→        await _profileStorage.setEmail(email);
   266→        await _profileStorage.setPassword(password);
   267→        return Failure.unconfirmedEmail(
   268→          code: methodFc.position('001'),
   269→          email: email,
   270→        );
   271→      case EmailVerificationStatus.notCreated:
   272→        return Failure.unregisteredEmail(
   273→          code: methodFc.position('002'),
   274→          email: email,
   275→        );
   276→      default:
   277→        return Failure.undefined(
   278→          code: methodFc.position('003'),
   279→          description: (l10n) => l10n.auth_client__unknown_verification_status,
   280→        );
   281→    }
   282→  }
