   285→
   286→  /// Sign out user from application
   287→  Future<Result<Failure, bool>> signOut() async {
   288→    // TODO: After disconnecting network,
   289→    // goTrueClient.signOut() throws a network exception at the first call,
   290→    // but this method return null without any exceptions at the second call.
   291→
   292→    // Run the query and return result.
   293→    final result = await _runner.runQuery(
   294→      () => AuthUtils.instance.signOut(),
   295→    );
   296→    // Delete cache regardless of the result
   297→    await Future.wait([
   298→      _profileStorage.setUserId(null),
   299→      _profileStorage.setTeamId(null),
   300→    ]);
   301→    if (result.hasLeft) {
   302→      return Left(result.left);
   303→    } else {
   304→      return const Right(true);
   305→    }
   306→  }
   307→
   308→  @override
   309→  Future<Result<Failure, bool>> changePassword(
   310→      {required String newPassword, required bool saveCredentials}) async {
   311→    // Run the query and return result.
   312→    final result = await _apiClient.request(
   313→      method: 'PUT',
   314→      path: '/users/me/password',
   315→      data: PasswordChangeRequest(
   316→        password: newPassword,
   317→        passwordConfirmation: newPassword,
   318→      ).toJson(),
   319→    );
   320→    if (result.hasLeft) {
   321→      return Left(result.left);
   322→    }
   323→
   324→    if (saveCredentials) {
   325→      // Save if we need to save credentials
   326→      await _profileStorage.setPassword(newPassword);
   327→    } else {
   328→      // Remove cached user password
   329→      await _profileStorage.setPassword(null);
   330→    }
   331→    return const Right(true);
   332→  }
   333→
   334→  @override
   335→  Future<Result<Failure, bool>> forgotPassword({required String email}) async {
   336→    // Run the query and return result.
   337→    final result = await _apiClient.request(
   338→      method: 'POST',
   339→      path: '/auth/password-reset/email',
   340→      data: PasswordResetRequest(
   341→        email: email,
   342→      ).toJson(),
   343→      authenticated: false,
   344→    );
   345→    if (result.hasLeft) {
   346→      return Left(result.left);
   347→    }
   348→    return const Right(true);
   349→  }
   350→
   351→  @override
   352→  Future<Result<Failure, String>> signUp({
   353→    required String email,
   354→    required String password,
   355→    DateTime? birthday,
   356→  }) async {
   357→    // Run the query and return result.
   358→    final result = await _apiClient.request(
   359→      method: 'POST',
   360→      path: '/auth/signup',
   361→      data: SignUpRequest(
   362→        name: email,
   363→        email: email,
   364→        password: password,
   365→        birthday: birthday,
   366→      ).toJson(),
   367→      responseMapper: SignUpResponse.fromJson,
   368→      authenticated: false,
   369→    );
   370→    if (result.hasLeft) {
   371→      return Left(result.left);
   372→    }
   373→
   374→    final userId = result.right.userId;
   375→    await Future.wait([
   376→      _profileStorage.setIsInSignUpFlow(true),
   377→      _profileStorage.setEmail(email),
   378→      _profileStorage.setPendingSignUpUserId(userId),
   379→      _profileStorage.setUserId(userId),
   380→      _profileStorage.setPassword(password),
   381→      _profileStorage.setBirthday(birthday),
   382→    ]);
   383→    return Right(userId);
   384→  }
   385→
   386→  @override
   387→  Future<Result<Failure, String>> verifyCode({
   388→    required String code,
   389→  }) async {
   390→    assert(_profileStorage.getIsInSignUpFlow() ?? false);
   391→
   392→    final email = await _profileStorage.getEmail();
   393→    assert(email != null);
   394→
   395→    // Run the query and return result.
   396→    final result = await _apiClient.request(
   397→      method: 'GET',
   398→      path: '/auth/code-verification',
   399→      queryParameters: VerifyCodeRequest(
   400→        email: email!,
   401→        code: code,
   402→      ).toJson(),
   403→      responseMapper: VerifyCodeResponse.fromJson,
   404→      authenticated: false,
   405→    );
   406→    if (result.hasLeft) {
   407→      return Left(result.left);
   408→    }
   409→    return Right(result.right.token);
   410→  }
   411→
   412→  @override
   413→  Future<Result<Failure, void>> completeSignUp({required String token}) async {
   414→    assert(_profileStorage.getIsInSignUpFlow() ?? false);
   415→
   416→    final pendingUserId = _profileStorage.getPendingSignUpUserId();
   417→    final userId = pendingUserId ?? _profileStorage.getUserId();
   418→    final password = await _profileStorage.getPassword();
   419→
   420→    assert(userId != null);
   421→    assert(password != null);
   422→
   423→    // Run the query and return result.
   424→    final result = await _apiClient.request(
   425→      method: 'PUT',
   426→      path: '/auth/password-reset/initial',
   427→      data: SetUserInitialPasswordRequest(
   428→        userId: userId!,
   429→        password: password!,
   430→        token: token,
   431→      ).toJson(),
   432→      authenticated: false,
   433→    );
   434→    await Future.wait([
   435→      _profileStorage.setIsInSignUpFlow(false),
   436→      _profileStorage.setPendingSignUpUserId(null),
   437→    ]);
   438→    if (result.hasLeft) {
   439→      return Left(result.left);
   440→    }
   441→    return Right(null);
   442→  }
   443→
   444→  @override
   445→  Future<Result<Failure, bool>> deleteAccount() async {
   446→    // Run the query and return result.
   447→    final result = await _apiClient.request(
   448→      method: 'DELETE',
   449→      path: '/users/me',
   450→    );
   451→    if (result.hasLeft) {
   452→      return Left(result.left);
   453→    }
   454→
   455→    // Sign out and clear all cached data after successful account deletion
   456→    await Future.wait([
   457→      AuthUtils.instance.signOut(),
   458→      _profileStorage.setUserId(null),
   459→      _profileStorage.setTeamId(null),
   460→      _profileStorage.setEmail(null),
   461→      _profileStorage.setPassword(null),
   462→      _profileStorage.setIsInSignUpFlow(false),
   463→    ]);
   464→
   465→    return const Right(true);
   466→  }
   467→
   468→  @override
   469→  Future<bool> get isLoggedIn async {
   470→    return await AuthUtils.instance.isSignedIn();
   471→  }
   472→}
